using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides web search capabilities to the research agent.
/// Uses a real HTTP client to fetch search results.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a given query. Returns a list of search result snippets with titles and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-5)")] int maxResults = 3)
    {
        maxResults = Math.Clamp(maxResults, 1, 5);

        try
        {
            // Use Wikipedia's API as a reliable, free search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit={maxResults}&format=json&utf8=1";

            var response = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(response);

            var results = new List<object>();
            foreach (var item in doc.RootElement.GetProperty("query").GetProperty("search").EnumerateArray())
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("snippet").GetString()
                    ?.Replace("<span class=\"searchmatch\">", "")
                    .Replace("</span>", "");

                results.Add(new
                {
                    Title = title,
                    Url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title ?? "")}",
                    Snippet = snippet,
                });
            }

            return results.Count > 0
                ? JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true })
                : "No results found for the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the full text content of a Wikipedia article by its title.")]
    public async Task<string> FetchArticleAsync(
        [Description("The exact Wikipedia article title")] string title)
    {
        try
        {
            var encoded = Uri.EscapeDataString(title);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&titles={encoded}&prop=extracts&explaintext=1&exintro=0&exsectionformat=plain&format=json&utf8=1";

            var response = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(response);

            var pages = doc.RootElement.GetProperty("query").GetProperty("pages");
            foreach (var page in pages.EnumerateObject())
            {
                if (page.Value.TryGetProperty("extract", out var extract))
                {
                    var text = extract.GetString() ?? "";
                    // Truncate to avoid exceeding token limits
                    return text.Length > 4000 ? text[..4000] + "\n\n[Content truncated...]" : text;
                }
            }

            return $"No article found with title: {title}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch article: {ex.Message}";
        }
    }
}

using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking capabilities so the agent can record
/// findings during research and retrieve them for summarization.
/// </summary>
public sealed class NoteTool
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Save a research note with a topic tag and content. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short topic tag for the note (e.g., 'history', 'key-facts')")] string topic,
        [Description("The content of the note")] string content)
    {
        _notes.Add(new NoteEntry(topic, content, DateTime.UtcNow));
        return $"Note saved under topic '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes. Use this before writing a final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var grouped = _notes.GroupBy(n => n.Topic);
        var output = new System.Text.StringBuilder();

        foreach (var group in grouped)
        {
            output.AppendLine($"## {group.Key}");
            foreach (var note in group)
            {
                output.AppendLine($"- {note.Content}");
            }
            output.AppendLine();
        }

        return output.ToString();
    }

    [Description("Get the count of saved notes, optionally filtered by topic.")]
    public string GetNoteCount(
        [Description("Optional topic filter. Leave empty to count all notes.")] string? topic = null)
    {
        var count = string.IsNullOrEmpty(topic)
            ? _notes.Count
            : _notes.Count(n => n.Topic.Equals(topic, StringComparison.OrdinalIgnoreCase));

        return string.IsNullOrEmpty(topic)
            ? $"Total notes: {count}"
            : $"Notes under '{topic}': {count}";
    }

    private sealed record NoteEntry(string Topic, string Content, DateTime Timestamp);
}

