        [Description("A short topic tag for the note (e.g., 'history', 'key-facts')")] string topic,
        [Description("The content of the note")] string content)
    {
        _notes.Add(new NoteEntry(topic, content, DateTime.UtcNow));
        return $"Note saved under topic '{topic}'. Total notes: {_notes.Count}.";
    }

    [Description("Retrieve all saved research notes. Use this before writing a final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var grouped = _notes.GroupBy(n => n.Topic);
        var output = new System.Text.StringBuilder();

        foreach (var group in grouped)
        {
            output.AppendLine($"## {group.Key}");
            foreach (var note in group)
            {
                output.AppendLine($"- {note.Content}");
            }
            output.AppendLine();
        }

        return output.ToString();
    }

    [Description("Get the count of saved notes, optionally filtered by topic.")]
    public string GetNoteCount(
        [Description("Optional topic filter. Leave empty to count all notes.")] string? topic = null)
    {
        var count = string.IsNullOrEmpty(topic)
            ? _notes.Count
            : _notes.Count(n => n.Topic.Equals(topic, StringComparison.OrdinalIgnoreCase));

        return string.IsNullOrEmpty(topic)
            ? $"Total notes: {count}"
            : $"Notes under '{topic}': {count}";
    }

    private sealed record NoteEntry(string Topic, string Content, DateTime Timestamp);
}

