using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

// --- Configuration ---
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OpenAI API key via AI:ApiKey in config or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

// --- Register services ---
builder.Services.AddHttpClient<WebSearchTool>();
builder.Services.AddSingleton<NoteTool>();

builder.Services.AddChatClient(b => b
    .UseLogging()
    .Use(new OpenAIClient(apiKey).AsChatClient(modelId)));

builder.Services.AddLogging(l => l
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

var host = builder.Build();

// --- Resolve services ---
var chatClient = host.Services.GetRequiredService<IChatClient>();
var webSearch = host.Services.GetRequiredService<WebSearchTool>();
var noteTool = host.Services.GetRequiredService<NoteTool>();
var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

// --- Build the agent with tools ---
var tools = new AIFunctionFactory[]
    {
        // Static method won't work; use instance methods
    }
    .ToList<object>(); // placeholder cleared below

var aiFunctions = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchWebAsync),
    AIFunctionFactory.Create(webSearch.FetchArticleAsync),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetAllNotes),
    AIFunctionFactory.Create(noteTool.GetNoteCount),
};

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the SearchWebAsync tool.
        2. Fetching full article content when you find promising results using FetchArticleAsync.
        3. Taking structured notes on key findings using the SaveNote tool.
        4. After gathering enough information, retrieving all notes with GetAllNotes.
        5. Producing a well-organized summary with key facts, important dates, and notable details.

        Always take notes as you research — do not try to remember everything.
        Cite your sources by including article titles or URLs.
        Aim for a comprehensive yet concise final summary.
        """,
    Tools = aiFunctions,
};

var agentOptions = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

// --- Run the research loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or      ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.Write("Research topic: ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.WriteLine($"\nResearching: {topic}...\n");

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    };

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, agentOptions))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
            {
                Console.Write(message.Text);
            }

            logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
                message.Role, message.Text?.Length ?? 0);
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError during research: {ex.Message}\n");
        logger.LogError(ex, "Agent invocation failed");
    }
}

